//! leech-vs-e8-shootout — K0 of the Kaiju validation track.
//!
//! Question (user, 2026-07-08): is the Kaiju (Leech-24) codebook enough
//! better than E8-family codebooks on REAL trained weights to supersede the
//! IQ wave? This bin measures the god-formula ledger directly:
//!
//!     weightedExcess = Σ_c H_c · (w_c − ŵ_c)²      (GodFormulaQuant.lean)
//!
//! on real qwen2.5-7b lm_head rows (Q6_K-dequantized from the local knot),
//! quantized at MATCHED rates by two ideal lattice quantizers:
//!
//!   * E8   — `nearest_e8_standard_point` (unit determinant, 8-dim blocks)
//!   * Λ24  — `nearest_leech` (det 2³⁶ Conway coords; per-dim unit-det
//!            normalizer √8), 24-dim blocks
//!
//! Rate matching: both lattices are used in their unit-determinant frames
//! with the SAME step `s`, so both spend the same nominal bits/dim; the
//! excess ratio at equal step isolates codebook geometry (G(Λ24)≈0.0658 vs
//! G(E8)≈0.0717 on white data; on real weights + real H is what we're here
//! to find out).
//!
//! H comes from the real llama.cpp imatrix (legacy binary format) for
//! `output.weight` — per-input-channel activation second moments, i.e. the
//! empirical diagonal Hessian. If the imatrix file is missing or in the
//! newer GGUF format, falls back to uniform H with a loud warning (the
//! comparison then reduces to plain MSE — still decision-relevant, weaker).
//!
//! Usage:
//!   cargo run --release --bin leech-vs-e8-shootout -- \
//!     [--knot ~/.edgework/models/qwen2.5-7b.knot] \
//!     [--imatrix /path/qwen2.5-7b-full.imatrix] \
//!     [--tensor output_weight.bin] [--rows 2048] \
//!     [--steps 0.5,0.75,1.0,1.5,2.0]

use std::collections::HashMap;
use std::fs::File;
use std::io::Read;

use distributed_inference::e8_quantizer::nearest_e8_standard_point;
use distributed_inference::leech_quantizer::{nearest_leech, LEECH_DIM};
use distributed_inference::loader::parse_knot_header_prefix;
use distributed_inference::math::dequantize_q6k_row;
use rayon::prelude::*;

/// Unit-determinant per-dim normalizer for the Conway integer Leech coords:
/// det(Λ24) = 2³⁶ ⇒ covolume^(1/24) = 2^1.5 = √8.
const LEECH_UNIT_NORM: f64 = 2.828427124746190; // sqrt(8)

fn parse_args() -> HashMap<String, String> {
    let mut out = HashMap::new();
    let args: Vec<String> = std::env::args().collect();
    let mut i = 1;
    while i + 1 < args.len() {
        if let Some(key) = args[i].strip_prefix("--") {
            out.insert(key.to_string(), args[i + 1].clone());
            i += 2;
        } else {
            i += 1;
        }
    }
    out
}

/// Parse a LEGACY llama.cpp imatrix file and return the per-channel values
/// for `tensor_name` (proportional to E[a_c²] — scale doesn't matter for
/// ratio comparisons). Returns None on GGUF-format files or missing entry.
fn load_imatrix_channel_h(path: &str, tensor_name: &str) -> Option<Vec<f32>> {
    let mut buf = Vec::new();
    File::open(path).ok()?.read_to_end(&mut buf).ok()?;
    if buf.len() < 4 {
        return None;
    }
    if &buf[0..4] == b"GGUF" {
        eprintln!("[imatrix] {path} is GGUF-format (newer llama.cpp writer) — parser TODO");
        return None;
    }
    let mut off = 0usize;
    let rd_i32 = |b: &[u8], o: &mut usize| -> Option<i32> {
        let v = i32::from_le_bytes(b.get(*o..*o + 4)?.try_into().ok()?);
        *o += 4;
        Some(v)
    };
    let n_entries = rd_i32(&buf, &mut off)?;
    if !(0..100_000).contains(&n_entries) {
        eprintln!("[imatrix] implausible entry count {n_entries} — unrecognized format");
        return None;
    }
    for _ in 0..n_entries {
        let name_len = rd_i32(&buf, &mut off)? as usize;
        let name = String::from_utf8_lossy(buf.get(off..off + name_len)?).to_string();
        off += name_len;
        let _ncall = rd_i32(&buf, &mut off)?;
        let nval = rd_i32(&buf, &mut off)? as usize;
        if name == tensor_name {
            let mut vals = Vec::with_capacity(nval);
            for k in 0..nval {
                let o = off + k * 4;
                vals.push(f32::from_le_bytes(buf.get(o..o + 4)?.try_into().ok()?));
            }
            return Some(vals);
        }
        off += nval * 4;
    }
    eprintln!("[imatrix] no entry named {tensor_name:?}");
    None
}

fn main() -> Result<(), String> {
    let args = parse_args();
    if args.get("mode").map(|m| m == "gap").unwrap_or(false) {
        return run_gap_mode(&args);
    }
    let home = std::env::var("HOME").unwrap_or_default();
    let knot_path = args
        .get("knot")
        .cloned()
        .unwrap_or_else(|| format!("{home}/.edgework/models/qwen2.5-7b.knot"));
    let tensor_name = args
        .get("tensor")
        .cloned()
        .unwrap_or_else(|| "blk_0_ffn_down_weight.bin".to_string());
    // Input-channel count of the tensor (imatrix H is per input channel).
    // ffn_down: 18944; lm_head/attn_output: 3584.
    let cols: usize = args.get("cols").and_then(|s| s.parse().ok()).unwrap_or(18944);
    // Name of the imatrix entry carrying this tensor's H (llama.cpp naming).
    let imatrix_entry = args
        .get("imatrix-entry")
        .cloned()
        .unwrap_or_else(|| "blk.0.ffn_down.weight".to_string());
    let n_rows: usize = args.get("rows").and_then(|s| s.parse().ok()).unwrap_or(2048);
    let steps: Vec<f64> = args
        .get("steps")
        .cloned()
        .unwrap_or_else(|| "0.5,0.75,1.0,1.5,2.0".to_string())
        .split(',')
        .filter_map(|s| s.trim().parse().ok())
        .collect();

    // ── Load tensor bytes straight off the knot (header + range read) ──
    let mut f = File::open(&knot_path).map_err(|e| format!("open {knot_path}: {e}"))?;
    let mut prefix = vec![0u8; 4 * 1024 * 1024];
    let got = f.read(&mut prefix).map_err(|e| e.to_string())?;
    prefix.truncate(got);
    let parsed = parse_knot_header_prefix(&prefix)?;
    let clean = tensor_name.replace(".bin", "");
    let info = parsed
        .tensors
        .get(&clean)
        .ok_or_else(|| format!("tensor {clean:?} not in knot TOC"))?;
    if info.tensor_type != "Q6_K" {
        return Err(format!(
            "shootout currently dequantizes Q6_K only; {clean} is {}",
            info.tensor_type
        ));
    }
    let bytes_per_row = cols / 256 * 210;
    let total_rows = (info.length as usize) / bytes_per_row;
    let take_rows = n_rows.min(total_rows);
    let row_stride = total_rows / take_rows; // deterministic spread over vocab

    use std::io::{Seek, SeekFrom};
    let mut tensor_bytes = vec![0u8; info.length as usize];
    f.seek(SeekFrom::Start(parsed.payload_offset as u64 + info.offset))
        .map_err(|e| e.to_string())?;
    f.read_exact(&mut tensor_bytes).map_err(|e| e.to_string())?;
    eprintln!(
        "[load] {clean}: {} bytes Q6_K, {total_rows} rows × {cols} cols; sampling {take_rows} rows (stride {row_stride})",
        info.length
    );

    // ── H: real imatrix if available ──
    let imatrix_path = args
        .get("imatrix")
        .cloned()
        .unwrap_or_else(|| format!("{home}/.edgework/models/qwen2.5-7b-ffndown.legacy.imatrix"));
    let h: Vec<f32> = match load_imatrix_channel_h(&imatrix_path, &imatrix_entry) {
        Some(v) if v.len() >= cols => {
            eprintln!("[imatrix] loaded real H ({} channels) from {imatrix_path}", v.len());
            v
        }
        _ => {
            eprintln!("[imatrix] WARNING: uniform H fallback — comparison is plain MSE");
            vec![1.0; cols]
        }
    };

    // Use a column span divisible by both 8 and 24 so E8 and Λ24 quantize
    // the IDENTICAL support: 3576 = 24·149 = 8·447.
    let span = (cols / LEECH_DIM) * LEECH_DIM;

    // Dequantize the sampled rows once.
    let rows: Vec<Vec<f32>> = (0..take_rows)
        .into_par_iter()
        .map(|k| {
            let r = k * row_stride;
            let mut out = vec![0.0f32; cols];
            dequantize_q6k_row(&mut out, &tensor_bytes, r, cols);
            out
        })
        .collect();

    // Normalize step against the data scale: express steps in units of the
    // weight std so the sweep lands in the meaningful rate band.
    let all_var: f64 = rows
        .iter()
        .flat_map(|r| r[..span].iter())
        .map(|&v| (v as f64) * (v as f64))
        .sum::<f64>()
        / (take_rows * span) as f64;
    let sigma = all_var.sqrt();
    eprintln!("[data] sigma = {sigma:.6}");

    println!(
        "{:>10} {:>16} {:>16} {:>10} {:>14} {:>14} {:>10}",
        "step/sigma", "E8 wExcess", "L24 wExcess", "wRatio", "E8 MSE", "L24 MSE", "mseRatio"
    );

    for &rel_step in &steps {
        let s = rel_step * sigma;
        let results: Vec<(f64, f64, f64, f64)> = rows
            .par_iter()
            .map(|row| {
                let mut e8_w = 0.0f64;
                let mut l24_w = 0.0f64;
                let mut e8_m = 0.0f64;
                let mut l24_m = 0.0f64;
                // E8 over 8-dim blocks.
                for b in (0..span).step_by(8) {
                    let mut y = [0.0f64; 8];
                    for i in 0..8 {
                        y[i] = row[b + i] as f64 / s;
                    }
                    let q = nearest_e8_standard_point(&y);
                    for i in 0..8 {
                        let err = (y[i] - q[i]) * s;
                        e8_w += h[b + i] as f64 * err * err;
                        e8_m += err * err;
                    }
                }
                // Λ24 over 24-dim blocks (same support).
                for b in (0..span).step_by(LEECH_DIM) {
                    let mut y = [0.0f64; LEECH_DIM];
                    for i in 0..LEECH_DIM {
                        y[i] = row[b + i] as f64 / s * LEECH_UNIT_NORM;
                    }
                    let q = nearest_leech(y);
                    for i in 0..LEECH_DIM {
                        let err = (y[i] - q[i] as f64) / LEECH_UNIT_NORM * s;
                        l24_w += h[b + i] as f64 * err * err;
                        l24_m += err * err;
                    }
                }
                (e8_w, l24_w, e8_m, l24_m)
            })
            .collect();
        let (e8_w, l24_w, e8_m, l24_m) = results.iter().fold(
            (0.0, 0.0, 0.0, 0.0),
            |acc, r| (acc.0 + r.0, acc.1 + r.1, acc.2 + r.2, acc.3 + r.3),
        );
        println!(
            "{:>10.3} {:>16.6e} {:>16.6e} {:>10.4} {:>14.6e} {:>14.6e} {:>10.4}",
            rel_step,
            e8_w,
            l24_w,
            l24_w / e8_w,
            e8_m,
            l24_m,
            l24_m / e8_m
        );
    }

    eprintln!(
        "[done] wRatio < 1.0 = Kaiju wins the god-formula ledger at that rate; \
         white-data theory predicts ~{:.3}",
        0.0658f64 / 0.0717f64
    );
    Ok(())
}

/// K2b "gap" mode: how far above the IDEAL lattice floor does practical
/// llama.cpp IQ2_S sit, in the weighted-excess ledger?
///
/// Inputs (produced by a python extraction step on Cloud Build):
///   --f32-rows FILE    raw little-endian f32, rows x cols (f16 ground truth,
///                      upcast) — the ORIGINAL weights
///   --iq2s-bytes FILE  the SAME rows quantized by llama.cpp as packed
///                      IQ2_S blocks (82 B / 256 elems)
///   --rows N --cols C  shape
///   --imatrix/--imatrix-entry  real H as in the main mode
///   --steps ...        ideal-lattice step sweep (rel. to sigma)
///
/// Output: excess(practical IQ2_S) as the horizontal reference, and the
/// ideal E8-box / Leech-box excess at each step — the step where the ideal
/// curves cross the IQ line, log2()-differenced, is the practical-IQ
/// inefficiency in bits/dim.
fn run_gap_mode(args: &std::collections::HashMap<String, String>) -> Result<(), String> {
    let f32_path = args.get("f32-rows").ok_or("gap mode needs --f32-rows")?;
    let iq_path = args.get("iq2s-bytes").ok_or("gap mode needs --iq2s-bytes")?;
    let n_rows: usize = args.get("rows").and_then(|s| s.parse().ok()).ok_or("--rows")?;
    let cols: usize = args.get("cols").and_then(|s| s.parse().ok()).ok_or("--cols")?;
    let steps: Vec<f64> = args
        .get("steps")
        .cloned()
        .unwrap_or_else(|| "0.4,0.6,0.8,1.0,1.4,2.0".to_string())
        .split(',')
        .filter_map(|s| s.trim().parse().ok())
        .collect();

    let mut raw = Vec::new();
    File::open(f32_path).map_err(|e| e.to_string())?.read_to_end(&mut raw).map_err(|e| e.to_string())?;
    if raw.len() != n_rows * cols * 4 {
        return Err(format!("--f32-rows size {} != rows*cols*4 = {}", raw.len(), n_rows * cols * 4));
    }
    let truth: Vec<f32> = raw
        .chunks_exact(4)
        .map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]]))
        .collect();

    let mut iq_bytes = Vec::new();
    File::open(iq_path).map_err(|e| e.to_string())?.read_to_end(&mut iq_bytes).map_err(|e| e.to_string())?;
    let bpr = cols / 256 * distributed_inference::iq_dequant::IQ2S_BLOCK_BYTES;
    if iq_bytes.len() != n_rows * bpr {
        return Err(format!("--iq2s-bytes size {} != rows*{} = {}", iq_bytes.len(), bpr, n_rows * bpr));
    }

    let imatrix_path = args.get("imatrix").cloned().unwrap_or_default();
    let imatrix_entry = args.get("imatrix-entry").cloned().unwrap_or_default();
    let h: Vec<f32> = match load_imatrix_channel_h(&imatrix_path, &imatrix_entry) {
        Some(v) if v.len() >= cols => {
            eprintln!("[imatrix] real H loaded ({} ch)", v.len());
            v
        }
        _ => {
            eprintln!("[imatrix] WARNING: uniform H fallback");
            vec![1.0; cols]
        }
    };

    let span = (cols / LEECH_DIM) * LEECH_DIM;

    // Practical IQ2_S excess (dequant real blocks vs truth).
    let iq_excess: f64 = (0..n_rows)
        .into_par_iter()
        .map(|r| {
            let mut row = vec![0.0f32; cols];
            distributed_inference::iq_dequant::dequantize_iq2s_row(&mut row, &iq_bytes, r, cols);
            let t = &truth[r * cols..(r + 1) * cols];
            let mut acc = 0.0f64;
            for c in 0..span {
                let e = (t[c] - row[c]) as f64;
                acc += h[c] as f64 * e * e;
            }
            acc
        })
        .sum();
    println!("practical IQ2_S weighted excess (2.5625 bpw incl. metadata): {iq_excess:.6e}");

    // ── Validation diagnostics ──
    // (1) UNWEIGHTED relative MSE: ||W - Ŵ||² / ||W||². Expected ~5-20% for
    //     a functioning 2.5-bpw quant; ~200% would mean the rows are
    //     misaligned and the headline number is an artifact.
    // (2) Excess share by H-decile: if the practical-IQ overhead is
    //     clipping-dominated, the top decile of H should carry most of it.
    let (num, den): (f64, f64) = (0..n_rows)
        .into_par_iter()
        .map(|r| {
            let mut row = vec![0.0f32; cols];
            distributed_inference::iq_dequant::dequantize_iq2s_row(&mut row, &iq_bytes, r, cols);
            let t = &truth[r * cols..(r + 1) * cols];
            let mut nn = 0.0f64;
            let mut dd = 0.0f64;
            for c in 0..span {
                let e = (t[c] - row[c]) as f64;
                nn += e * e;
                dd += (t[c] as f64) * (t[c] as f64);
            }
            (nn, dd)
        })
        .reduce(|| (0.0, 0.0), |a, b| (a.0 + b.0, a.1 + b.1));
    println!(
        "VALIDATION: unweighted relative MSE = {:.4} ({:.2}% of signal energy)",
        num / den,
        100.0 * num / den
    );

    // H-decile boundaries over the columns in span.
    let mut h_sorted: Vec<f32> = h[..span].to_vec();
    h_sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let decile_lo = |d: usize| h_sorted[(span - 1) * d / 10];
    let mut decile_excess = [0.0f64; 10];
    for r in 0..n_rows {
        let mut row = vec![0.0f32; cols];
        distributed_inference::iq_dequant::dequantize_iq2s_row(&mut row, &iq_bytes, r, cols);
        let t = &truth[r * cols..(r + 1) * cols];
        for c in 0..span {
            let e = (t[c] - row[c]) as f64;
            let x = h[c] as f64 * e * e;
            // Find decile of h[c] (linear scan over 10 boundaries — fine).
            let mut d = 9;
            for k in (0..10).rev() {
                if h[c] >= decile_lo(k) {
                    d = k;
                    break;
                }
            }
            decile_excess[d] += x;
        }
    }
    let total: f64 = decile_excess.iter().sum();
    print!("VALIDATION: excess share by H-decile (low→high): ");
    for d in 0..10 {
        print!("{:.1}% ", 100.0 * decile_excess[d] / total.max(1e-30));
    }
    println!();

    // ── KAIJU1 head-to-head: same rows, same H, our codec ──
    {
        use distributed_inference::kaiju_format;
        let t0 = std::time::Instant::now();
        let (kj_bytes, kj_clamp) =
            kaiju_format::encode_kaiju1(&truth, n_rows, cols, &h[..cols], 0.10, 0);
        let kj_bpw = kj_bytes.len() as f64 * 8.0 / (n_rows * cols) as f64;
        let kj_excess: f64 = (0..n_rows)
            .map(|r| {
                let mut row = vec![0.0f32; cols];
                kaiju_format::dequantize_kaiju1_row(&mut row, &kj_bytes, r, cols);
                let t = &truth[r * cols..(r + 1) * cols];
                let mut acc = 0.0f64;
                for c in 0..span {
                    let e = (t[c] - row[c]) as f64;
                    acc += h[c] as f64 * e * e;
                }
                acc
            })
            .sum();
        println!(
            "KAIJU1 v1: weighted excess = {:.6e} at {:.3} bpw (clamp {:.4}, encode {:.1}s) — KJ/IQ = {:.4}",
            kj_excess,
            kj_bpw,
            kj_clamp,
            t0.elapsed().as_secs_f64(),
            kj_excess / iq_excess
        );
    }

    let all_var: f64 = (0..n_rows)
        .flat_map(|r| truth[r * cols..r * cols + span].iter())
        .map(|&v| (v as f64) * (v as f64))
        .sum::<f64>()
        / (n_rows * span) as f64;
    let sigma = all_var.sqrt();
    eprintln!("[data] sigma = {sigma:.6}");

    println!(
        "{:>10} {:>16} {:>16} {:>12} {:>12}",
        "step/sigma", "idealE8 wExcess", "idealL24 wExcess", "E8/IQ", "L24/IQ"
    );
    for &rel_step in &steps {
        let s = rel_step * sigma;
        let (e8_w, l24_w) = (0..n_rows)
            .into_par_iter()
            .map(|r| {
                let t = &truth[r * cols..(r + 1) * cols];
                let mut e8 = 0.0f64;
                let mut l24 = 0.0f64;
                for b in (0..span).step_by(8) {
                    let mut y = [0.0f64; 8];
                    for i in 0..8 {
                        y[i] = t[b + i] as f64 / s;
                    }
                    let q = nearest_e8_standard_point(&y);
                    for i in 0..8 {
                        let err = (y[i] - q[i]) * s;
                        e8 += h[b + i] as f64 * err * err;
                    }
                }
                for b in (0..span).step_by(LEECH_DIM) {
                    let mut y = [0.0f64; LEECH_DIM];
                    for i in 0..LEECH_DIM {
                        y[i] = t[b + i] as f64 / s * LEECH_UNIT_NORM;
                    }
                    let q = nearest_leech(y);
                    for i in 0..LEECH_DIM {
                        let err = (y[i] - q[i] as f64) / LEECH_UNIT_NORM * s;
                        l24 += h[b + i] as f64 * err * err;
                    }
                }
                (e8, l24)
            })
            .reduce(|| (0.0, 0.0), |a, b| (a.0 + b.0, a.1 + b.1));
        println!(
            "{:>10.3} {:>16.6e} {:>16.6e} {:>12.4} {:>12.4}",
            rel_step, e8_w, l24_w, e8_w / iq_excess, l24_w / iq_excess
        );
    }
    eprintln!(
        "[read] find the step where E8/IQ crosses 1.0; each doubling of step = 1 bit/dim. \
         The log2 of that crossing step vs IQ's effective step = practical-IQ overhead in bits."
    );
    Ok(())
}
